4. rhyhorn.ts: key:'rhyhorn', name:'Rhyhorn', sprite:SPRITES.rhyhorn, hp:120, speed:25, damage:22, xpValue:55, scale:1.2, behavior:'rammer', contactEffect:{type:'knockback', durationMs:300, force:300}
5. weezing.ts: key:'weezing', name:'Weezing', sprite:SPRITES.weezing, hp:180, speed:25, damage:15, xpValue:100, scale:1.3, behavior:'gasSpreader', deathCloud:{radius:70, dps:5, durationMs:6000}
6. magneton.ts: key:'magneton', name:'Magneton', sprite:SPRITES.magneton, hp:100, speed:45, damage:14, xpValue:95, scale:1.0, behavior:'pullerElite'
7. tentacruel.ts: key:'tentacruel', name:'Tentacruel', sprite:SPRITES.tentacruel, hp:130, speed:50, damage:16, xpValue:105, scale:1.2, behavior:'trapperElite', contactEffect:{type:'stun', durationMs:2500}
8. rhydon.ts: key:'rhydon', name:'Rhydon', sprite:SPRITES.rhydon, hp:250, speed:20, damage:35, xpValue:110, scale:1.4, behavior:'rammer', contactEffect:{type:'knockback', durationMs:500, force:400}
